args.sparql:
SELECT ?country ?countryName ?taxRate WHERE {
  ?country wdt:P31 wd:Q6256 .
  ?country wdt:P1595 ?taxRate .
  ?country rdfs:label ?countryName .
  FILTER(LANG(?countryName) = "en")
} ORDER BY DESC(?taxRate) LIMIT 1

